parameters.text:
=Evaluate this RAG agent response:

QUESTION: {{ $json.question }}
QUESTION ID: {{ $json.id }}
REQUIRED SECTIONS: {{ JSON.stringify($json.source_sections) }}
EXPECTED CITATION: {{ $json.expected_citation }}

AGENT ANSWER:
{{ $json.agent_answer }}

Execute in order:
1. Call citation_checker with the agent answer string
2. Call snorkel_rubric_evaluator with: {"response":"<agent answer>","expected_sections":<sections array>}
3. final_score = (citation_score * 0.4) + (rubric_score * 0.6)
4. passed = final_score >= 75
5. If failed, set failure_mode: citation_missing | wrong_section | reasoning_gap | hallucination | edge_case

parameters.jsCode:
const response = query;
const patterns = [/\[Page\s+\d+\]/gi, /\[Section\s+[\d.]+\]/gi, /\[Clause\s+[\d.]+\]/gi, /\(p\.\s*\d+\)/gi];
const found = [];
for (const p of patterns) { const m = response.match(p) || []; found.push(...m); }
const unique = [...new Set(found)];
return JSON.stringify({ citation_found: unique.length > 0, citations_list: unique, citation_score: Math.min(100, unique.length * 25) });

const input = JSON.parse(query);
const { response = "", expected_sections = [] } = input;
let score = 0;
const completeness = response.split(" ").length > 30;
const sectionCoverage = expected_sections.some(s => response.toLowerCase().includes(s.toLowerCase()));
const conflictResolution = /however|conflict|supersede|notwithstanding|despite/i.test(response);
const legalPrecision = /shall|must|liable|obligation|breach/i.test(response);
if (completeness) score += 25;
if (sectionCoverage) score += 35;
if (conflictResolution) score += 25;
if (legalPrecision) score += 15;
return JSON.stringify({ rubric_score: score, rubric_passed: score >= 60, grade: score >= 80 ? "PASS" : score >= 60 ? "MARGINAL" : "FAIL", details: { completeness, section_coverage: sectionCoverage, conflict_resolution: conflictResolution, legal_precision: legalPrecision } });

const results = $input.all()[0].json.eval_results || [];
const total = results.length;
const passed = results.filter(r => r.eval_passed === true).length;
const passRate = total > 0 ? Math.round((passed / total) * 100) : 0;
const avgScore = total > 0 ? Math.round(results.reduce((s, r) => s + (r.eval_score || 0), 0) / total) : 0;
const failedItems = results.filter(r => !r.eval_passed).map(r => ({ question: r.question, failure_mode: r.failure_mode, score: r.eval_score, reasoning: r.eval_reasoning }));
return [{ json: { eval_run_id: $input.all()[0].json.eval_run_id || "unknown", total_questions: total, passed_count: passed, failed_count: total - passed, pass_rate: passRate, average_score: avgScore, production_ready: passRate >= 90, failed_items: failedItems, evaluated_at: new Date().toISOString() } }];
